export function getTransitionCurve(from: string, to: string): number[][] | null {
  return TRANSITION_CURVES[`${from}_${to}`] ?? null
}

export function interpolateTransition(curve: number[][], t: number): number[] {
  const idx = Math.max(0, Math.min(1, t)) * (curve.length - 1)
  const lo = Math.floor(idx), hi = Math.min(lo + 1, curve.length - 1)
  const frac = idx - lo
  return curve[lo].map((v, i) => v * (1 - frac) + curve[hi][i] * frac)
}
